233→
234→export const useFileMentions = ({
235→  text,
236→  setText,
237→  textareaRef,
238→  attachments,
239→  sessionId,
240→  listDirectory,
241→}: UseFileMentionsArgs): UseFileMentionsReturn => {
242→  const [range, setRange] = useState<MentionRange | null>(null);
243→  const [activeIndex, setActiveIndex] = useState(0);
244→  const [workspaceFiles, setWorkspaceFiles] = useState<WorkspaceFile[]>([]);
245→  const [workspaceStatus, setWorkspaceStatus] = useState<
246→    "idle" | "loading" | "ready" | "error"
247→  >("idle");
248→  const [workspaceError, setWorkspaceError] = useState<string | null>(null);
249→  const workspaceRequestRef = useRef(0);
250→  const lastLoadedRef = useRef(0);
251→  const directoryQueryTimerRef = useRef<ReturnType<typeof setTimeout> | null>(
252→    null,
253→  );
254→  const [directoryFiles, setDirectoryFiles] = useState<WorkspaceFile[]>([]);
255→
256→  const attachmentOptions = useMemo(
257→    () => toAttachmentOptions(attachments),
258→    [attachments],
259→  );
260→  const mergedWorkspaceFiles = useMemo(() => {
261→    if (directoryFiles.length === 0) {
262→      return workspaceFiles;
263→    }
264→    const existing = new Set(workspaceFiles.map((f) => f.path));
265→    const extra = directoryFiles.filter((f) => !existing.has(f.path));
266→    return extra.length === 0 ? workspaceFiles : [...workspaceFiles, ...extra];
267→  }, [workspaceFiles, directoryFiles]);
268→
269→  const workspaceOptions = useMemo(
270→    () => toWorkspaceOptions(mergedWorkspaceFiles),
271→    [mergedWorkspaceFiles],
272→  );
273→
274→  const sections = useMemo(() => {
275→    const attachmentsSection = filterOptions(
276→      attachmentOptions,
277→      range?.query ?? "",
278→      0,
279→    );
280→    const workspaceSection = filterOptions(
281→      workspaceOptions,
282→      range?.query ?? "",
283→      attachmentsSection.length,
284→    );
285→    return {
286→      attachments: attachmentsSection,
287→      workspace: workspaceSection,
288→    };
289→  }, [attachmentOptions, workspaceOptions, range?.query]);
290→
291→  const flatOptions = useMemo(
292→    () => [...sections.attachments, ...sections.workspace],
293→    [sections.attachments, sections.workspace],
294→  );
295→
296→  useEffect(() => {
297→    if (activeIndex < flatOptions.length) {
298→      return;
299→    }
300→    setActiveIndex(flatOptions.length === 0 ? 0 : flatOptions.length - 1);
301→  }, [activeIndex, flatOptions.length]);
302→
303→  useEffect(() => {
304→    setActiveIndex(0);
305→  }, []);
306→
307→  // biome-ignore lint/correctness/useExhaustiveDependencies: reset workspace when sessionId changes
308→  useEffect(() => {
309→    setWorkspaceFiles([]);
310→    setWorkspaceStatus("idle");
311→    setWorkspaceError(null);
312→    workspaceRequestRef.current += 1;
313→    lastLoadedRef.current = 0;
314→  }, [sessionId]);
315→
316→  const loadWorkspaceFiles = useCallback(async () => {
317→    if (!(sessionId && listDirectory)) {
318→      return;
319→    }
320→    setWorkspaceStatus("loading");
321→    setWorkspaceError(null);
322→    workspaceRequestRef.current += 1;
323→    const requestId = workspaceRequestRef.current;
324→    try {
325→      const files = await crawlWorkspace({ sessionId, listDirectory });
326→      if (workspaceRequestRef.current !== requestId) {
327→        return;
328→      }
329→      setWorkspaceFiles(files);
330→      setWorkspaceStatus("ready");
331→      lastLoadedRef.current = Date.now();
332→    } catch (error) {
333→      if (workspaceRequestRef.current !== requestId) {
334→        return;
335→      }
336→      setWorkspaceStatus("error");
337→      setWorkspaceError(
338→        error instanceof Error
339→          ? error.message
340→          : "Failed to load workspace files",
341→      );
342→    }
343→  }, [sessionId, listDirectory]);
344→
345→  useEffect(() => {
346→    if (!range) {
347→      return;
348→    }
349→    if (!(sessionId && listDirectory)) {
350→      return;
351→    }
352→    if (workspaceStatus === "loading") {
353→      return;
354→    }
355→    const isStale =
356→      workspaceStatus === "ready" &&
357→      Date.now() - lastLoadedRef.current > WORKSPACE_STALE_MS;
358→    if (workspaceStatus !== "idle" && !isStale) {
359→      return;
360→    }
361→    loadWorkspaceFiles();
362→    // eslint-disable-next-line react-hooks/exhaustive-deps
363→  }, [range, sessionId, listDirectory, workspaceStatus, loadWorkspaceFiles]);
364→
365→  // Debounced directory query when query contains "/"
366→  useEffect(() => {
367→    if (directoryQueryTimerRef.current) {
368→      clearTimeout(directoryQueryTimerRef.current);
369→      directoryQueryTimerRef.current = null;
370→    }
371→    const query = range?.query ?? "";
372→    const slashIndex = query.lastIndexOf("/");
373→    if (slashIndex < 0 || !(sessionId && listDirectory)) {
374→      setDirectoryFiles([]);
375→      return;
376→    }
377→    const dirPrefix = query.slice(0, slashIndex);
378→    const dirPath = dirPrefix === "" ? undefined : dirPrefix;
379→    directoryQueryTimerRef.current = setTimeout(async () => {
380→      try {
381→        const entries = await listDirectory(sessionId, dirPath);
382→        const files: WorkspaceFile[] = [];
383→        for (const entry of entries) {
384→          if (entry.type === "directory") {
385→            continue;
386→          }
387→          const fullPath = dirPath
388→            ? `${dirPath}/${entry.name}`
389→            : entry.name;
390→          files.push({ path: fullPath, size: entry.size });
391→        }
392→        setDirectoryFiles(files);
393→      } catch {
394→        // Silently ignore — the main index is still available
395→      }
396→    }, DIRECTORY_QUERY_DEBOUNCE_MS);
397→    return () => {
398→      if (directoryQueryTimerRef.current) {
399→        clearTimeout(directoryQueryTimerRef.current);
400→        directoryQueryTimerRef.current = null;
401→      }
402→    };
403→  }, [range?.query, sessionId, listDirectory]);
404→
405→  useEffect(() => {
406→    const caret = textareaRef.current?.selectionStart ?? text.length;
407→    const next = detectMention(text, caret);
408→    setRange((previous) => (isSameRange(previous, next) ? previous : next));
409→  }, [text, textareaRef]);
410→
411→  const handleTextChange = useCallback(
412→    (value: string, caret: number | null) => {
413→      setRange(detectMention(value, caret));
414→    },
415→    [],
416→  );
417→
418→  const handleCaretChange = useCallback(
419→    (caret: number | null) => {
420→      setRange(detectMention(text, caret));
421→    },
422→    [text],
423→  );
424→
425→  const closeMenu = useCallback(() => {
426→    setRange(null);
427→  }, []);
428→
429→  const selectOption = useCallback(
430→    (option?: MentionOption) => {
431→      if (!range) {
432→        return;
433→      }
434→      const target = option ?? flatOptions[activeIndex];
435→      if (!target) {
436→        return;
437→      }
438→
439→      const mentionText = `@${target.insertValue}`;
440→      const before = text.slice(0, range.start);
441→      const after = text.slice(range.end);
442→      const needsSpace =
443→        after.length === 0 || NON_WHITESPACE_START.test(after) ? " " : "";
444→      const nextValue = `${before}${mentionText}${needsSpace}${after}`;
445→      const nextCaret = before.length + mentionText.length + needsSpace.length;
446→
447→      setText(nextValue);
448→      setRange(null);
449→      setActiveIndex(0);
450→
451→      requestAnimationFrame(() => {
452→        const node = textareaRef.current;
453→        if (!node) {
454→          return;
455→        }
456→        node.focus();
457→        node.setSelectionRange(nextCaret, nextCaret);
458→      });
459→    },
460→    [range, flatOptions, activeIndex, text, setText, textareaRef],
461→  );
462→
463→  const handleKeyDown = useCallback(
464→    (event: KeyboardEvent<HTMLTextAreaElement>) => {
465→      if (!range) {
466→        return;
467→      }
468→
469→      if (event.key === "ArrowDown") {
470→        if (flatOptions.length === 0) {
471→          return;
472→        }
473→        event.preventDefault();
474→        setActiveIndex((previous) => (previous + 1) % flatOptions.length);
475→        return;
476→      }
477→
478→      if (event.key === "ArrowUp") {
479→        if (flatOptions.length === 0) {
480→          return;
481→        }
482→        event.preventDefault();
483→        setActiveIndex((previous) =>
484→          previous - 1 < 0
485→            ? flatOptions.length - 1
486→            : (previous - 1) % flatOptions.length,
487→        );
488→        return;
489→      }
490→
491→      if (event.key === "Enter" || event.key === "Tab") {
492→        if (flatOptions.length === 0) {
493→          return;
494→        }
495→        event.preventDefault();
496→        selectOption();
497→        return;
498→      }
499→
500→      if (event.key === "Escape") {
501→        event.preventDefault();
502→        closeMenu();
503→      }
504→    },
505→    [range, flatOptions, selectOption, closeMenu],
506→  );
507→
508→  const retryWorkspace = useCallback(() => {
509→    loadWorkspaceFiles();
510→  }, [loadWorkspaceFiles]);
511→
512→  return {
513→    isOpen: Boolean(range),
514→    query: range?.query ?? "",
515→    flatOptions,
516→    sections,
517→    activeIndex,
518→    setActiveIndex,
519→    handleTextChange,
520→    handleCaretChange,
521→    handleKeyDown,
522→    selectOption,
523→    closeMenu,
524→    workspaceStatus,
525→    workspaceError,
526→    retryWorkspace,
527→    workspaceFileCount: workspaceFiles.length,
528→  };
529→};
530→

