  const [workspaceError, setWorkspaceError] = useState<string | null>(null);
  const workspaceRequestRef = useRef(0);
  const lastLoadedRef = useRef(0);
  const directoryQueryTimerRef = useRef<ReturnType<typeof setTimeout> | null>(
